import{_ as s,c as t,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse(`{"title":"Récupération après compression : Restauration automatique des compétences | opencode-agent-skills","description":"Apprenez le mécanisme de récupération après compression d'opencode-agent-skills. Restauration automatique de la liste des compétences après compression de session, utilisation de messages synthétiques pour maintenir les compétences disponibles.","frontmatter":{"title":"Récupération après compression : Restauration automatique des compétences | opencode-agent-skills","sidebarTitle":"Compétences conservées après compression","subtitle":"Récupération après compression : Restauration automatique des compétences","description":"Apprenez le mécanisme de récupération après compression d'opencode-agent-skills. Restauration automatique de la liste des compétences après compression de session, utilisation de messages synthétiques pour maintenir les compétences disponibles.","tags":["Gestion du contexte","Persistance de session","Fonctionnalités avancées"],"prerequisite":["platforms-loading-skills-into-context"],"order":4},"headers":[],"relativePath":"fr/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md","filePath":"fr/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"}`),o={name:"fr/joshuadavidthomas/opencode-agent-skills/advanced/context-compaction-resilience/index.md"};function a(r,e,l,c,p,u){return n(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="mecanisme-de-recuperation-apres-compression-de-contexte" tabindex="-1">Mécanisme de récupération après compression de contexte <a class="header-anchor" href="#mecanisme-de-recuperation-apres-compression-de-contexte" aria-label="Permalink to &quot;Mécanisme de récupération après compression de contexte&quot;">​</a></h1><h2 id="ce-que-vous-pourrez-faire-apres-ce-cours" tabindex="-1">Ce que vous pourrez faire après ce cours <a class="header-anchor" href="#ce-que-vous-pourrez-faire-apres-ce-cours" aria-label="Permalink to &quot;Ce que vous pourrez faire après ce cours&quot;">​</a></h2><ul><li>Comprendre comment le plugin maintient les compétences disponibles après la compression de session</li><li>Connaître le moment de déclenchement et le flux d&#39;exécution de la récupération après compression</li><li>Être capable de vérifier si la récupération après compression fonctionne correctement</li><li>Comprendre le rôle des messages synthétiques dans le mécanisme de récupération</li></ul><h2 id="votre-probleme-actuel" tabindex="-1">Votre problème actuel <a class="header-anchor" href="#votre-probleme-actuel" aria-label="Permalink to &quot;Votre problème actuel&quot;">​</a></h2><p>Dans les longues sessions, OpenCode effectue une <strong>compression de contexte</strong> (Context Compaction) pour économiser les tokens. Après compression, la session ne conserve que les messages récents, et l&#39;historique précoce (y compris le contenu des compétences précédemment injectées) est supprimé.</p><p>Cela pose un problème : si le contenu des compétences est éliminé par la compression, l&#39;IA ne sait plus quelles compétences sont disponibles et ne peut pas utiliser les compétences chargées.</p><h2 id="quand-utiliser-cette-solution" tabindex="-1">Quand utiliser cette solution <a class="header-anchor" href="#quand-utiliser-cette-solution" aria-label="Permalink to &quot;Quand utiliser cette solution&quot;">​</a></h2><p>Le mécanisme de récupération après compression fonctionne <strong>automatiquement</strong>, sans nécessiter d&#39;intervention manuelle. Cependant, en comprenant son fonctionnement, vous pouvez résoudre des problèmes dans les scénarios suivants :</p><ul><li>L&#39;IA &quot;oublie&quot; soudainement les compétences lors de longues sessions</li><li>Besoin de déboguer la disponibilité des compétences après compression</li><li>Comprendre les stratégies de gestion de session du plugin</li></ul><h2 id="concept-central" tabindex="-1">Concept central <a class="header-anchor" href="#concept-central" aria-label="Permalink to &quot;Concept central&quot;">​</a></h2><h3 id="qu-est-ce-que-la-compression-de-contexte" tabindex="-1">Qu&#39;est-ce que la compression de contexte ? <a class="header-anchor" href="#qu-est-ce-que-la-compression-de-contexte" aria-label="Permalink to &quot;Qu&#39;est-ce que la compression de contexte ?&quot;">​</a></h3><p>À mesure que les messages s&#39;accumulent dans une session OpenCode, celle-ci devient de plus en plus longue. Lorsque l&#39;utilisation des tokens approche la limite, le système effectue automatiquement une <strong>compression de contexte</strong> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Session initiale] → [Message 1] → [Message 2] → ... → [Message 50]</span></span>
<span class="line"><span>                          ↑ Point de compression : ne conserver que les 10 derniers messages</span></span></code></pre></div><p>Après compression, les messages précoces (y compris le contenu injecté des compétences) sont supprimés, et l&#39;IA ne voit que l&#39;historique des messages récents.</p><h3 id="fonctionnement-du-mecanisme-de-recuperation-apres-compression" tabindex="-1">Fonctionnement du mécanisme de récupération après compression <a class="header-anchor" href="#fonctionnement-du-mecanisme-de-recuperation-apres-compression" aria-label="Permalink to &quot;Fonctionnement du mécanisme de récupération après compression&quot;">​</a></h3><p>Le plugin écoute l&#39;événement <code>session.compacted</code>. Dès qu&#39;une compression est détectée, il exécute immédiatement les opérations de récupération suivantes :</p><div class="language-mermaid vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">mermaid</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">graph TD</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    A[Déclenchement de compression de session] --&gt; B[Événement session.compacted]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    B --&gt; C{Superpowers activé ?}</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Oui| D[Réinjecter l&#39;invite Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    C --&gt;|Non| E[Ignorer Superpowers]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    D --&gt; F[Réinjecter la liste des compétences]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    E --&gt; F</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    F --&gt; G[Vider l&#39;enregistrement des compétences chargées]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    G --&gt; H[Récupération terminée]</span></span></code></pre></div><p><strong>Points clés</strong> :</p><ul><li>La récupération est <strong>automatique</strong>, pas besoin de déclenchement manuel</li><li>La liste des compétences récupérées contient <strong>toutes les compétences découvertes</strong> (pas seulement celles précédemment chargées)</li><li>L&#39;enregistrement des compétences chargées est vidé, permettant à l&#39;IA de réévaluer quelles compétences sont nécessaires</li></ul><h3 id="role-des-messages-synthetiques" tabindex="-1">Rôle des messages synthétiques <a class="header-anchor" href="#role-des-messages-synthetiques" aria-label="Permalink to &quot;Rôle des messages synthétiques&quot;">​</a></h3><p>Le plugin utilise le mécanisme d&#39;<strong>injection de messages synthétiques</strong> (Synthetic Message Injection) pour injecter du contenu :</p><table tabindex="0"><thead><tr><th>Attribut</th><th>Valeur</th><th>Signification</th></tr></thead><tbody><tr><td><code>noReply</code></td><td><code>true</code></td><td>L&#39;IA ne répondra pas au contenu injecté lui-même</td></tr><tr><td><code>synthetic</code></td><td><code>true</code></td><td>Marqué comme contenu généré par le système, ne compte pas comme entrée utilisateur, ne s&#39;affiche pas dans l&#39;interface</td></tr></tbody></table><p>Cela signifie que le contenu injecté lors de la récupération après compression :</p><ul><li>Est complètement transparent pour l&#39;utilisateur (invisible)</li><li>Ne consomme pas le quota de messages utilisateur</li><li>Mais est lu et compris par l&#39;IA</li></ul><h2 id="🎒-preparation-avant-de-commencer" tabindex="-1">🎒 Préparation avant de commencer <a class="header-anchor" href="#🎒-preparation-avant-de-commencer" aria-label="Permalink to &quot;🎒 Préparation avant de commencer&quot;">​</a></h2><p>Ce cours nécessite :</p><ul><li>Plugin OpenCode Agent Skills installé</li><li>Compréhension des bases du chargement des compétences</li><li>Une longue session pour tester l&#39;effet de compression</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>Aucune préparation supplémentaire n&#39;est nécessaire, le mécanisme de récupération après compression est une fonctionnalité intégrée du plugin.</p></div><h2 id="suivez-les-etapes-verifier-l-effet-de-recuperation-apres-compression" tabindex="-1">Suivez les étapes : Vérifier l&#39;effet de récupération après compression <a class="header-anchor" href="#suivez-les-etapes-verifier-l-effet-de-recuperation-apres-compression" aria-label="Permalink to &quot;Suivez les étapes : Vérifier l&#39;effet de récupération après compression&quot;">​</a></h2><h3 id="etape-1-demarrer-une-nouvelle-session" tabindex="-1">Étape 1 : Démarrer une nouvelle session <a class="header-anchor" href="#etape-1-demarrer-une-nouvelle-session" aria-label="Permalink to &quot;Étape 1 : Démarrer une nouvelle session&quot;">​</a></h3><p><strong>Pourquoi</strong> Vérifier que la liste des compétences est injectée normalement lors de l&#39;initialisation de la session</p><p>Démarrez une nouvelle session et entrez n&#39;importe quel message :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bonjour</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : L&#39;IA répond normalement, et en arrière-plan, la liste des compétences est automatiquement injectée (invisible pour l&#39;utilisateur)</p><h3 id="etape-2-charger-une-competence" tabindex="-1">Étape 2 : Charger une compétence <a class="header-anchor" href="#etape-2-charger-une-competence" aria-label="Permalink to &quot;Étape 2 : Charger une compétence&quot;">​</a></h3><p><strong>Pourquoi</strong> S&#39;assurer que le contenu de la compétence est injecté dans le contexte</p><p>Appelez l&#39;outil <code>use_skill</code> :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utilisez get_available_skills pour voir les compétences disponibles, puis utilisez use_skill pour charger l&#39;une d&#39;entre elles</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> : L&#39;IA liste les compétences disponibles, puis charge la compétence que vous avez choisie</p><h3 id="etape-3-declencher-la-compression-de-contexte" tabindex="-1">Étape 3 : Déclencher la compression de contexte <a class="header-anchor" href="#etape-3-declencher-la-compression-de-contexte" aria-label="Permalink to &quot;Étape 3 : Déclencher la compression de contexte&quot;">​</a></h3><p><strong>Pourquoi</strong> Simuler un scénario de longue session, déclencher le mécanisme de compression d&#39;OpenCode</p><p>Envoyez continuellement des messages pour simuler une longue conversation :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Message 1 : Contenu de test</span></span>
<span class="line"><span>Message 2 : Continuer les tests</span></span>
<span class="line"><span>...</span></span>
<span class="line"><span>(Répéter l&#39;envoi de 20 à 30 messages)</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>À mesure que les messages augmentent, l&#39;historique de session s&#39;allonge</li><li>Après avoir atteint une certaine longueur, OpenCode effectue automatiquement la compression</li><li>Après compression, les messages précoces (y compris l&#39;injection des compétences) sont supprimés</li></ul><h3 id="etape-4-verifier-l-effet-de-recuperation" tabindex="-1">Étape 4 : Vérifier l&#39;effet de récupération <a class="header-anchor" href="#etape-4-verifier-l-effet-de-recuperation" aria-label="Permalink to &quot;Étape 4 : Vérifier l&#39;effet de récupération&quot;">​</a></h3><p><strong>Pourquoi</strong> Vérifier que la liste des compétences est réinjectée après compression</p><p>Après compression, demandez à l&#39;IA d&#39;utiliser une compétence à nouveau :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Aide-moi à utiliser la compétence git-helper pour créer une nouvelle branche (en supposant que vous ayez installé la compétence git-helper)</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>L&#39;IA sait toujours quelles compétences sont disponibles (prouvant que la liste des compétences a été récupérée)</li><li>L&#39;IA peut charger et utiliser les compétences normalement (prouvant que les fonctionnalités des compétences ne sont pas affectées par la compression)</li></ul><h3 id="etape-5-verifier-l-injection-de-messages-synthetiques" tabindex="-1">Étape 5 : Vérifier l&#39;injection de messages synthétiques <a class="header-anchor" href="#etape-5-verifier-l-injection-de-messages-synthetiques" aria-label="Permalink to &quot;Étape 5 : Vérifier l&#39;injection de messages synthétiques&quot;">​</a></h3><p><strong>Pourquoi</strong> Confirmer que le mécanisme de récupération utilise des messages synthétiques et n&#39;interfère pas avec la conversation</p><p>Si le plugin le prend en charge, vous pouvez vérifier l&#39;historique des messages de session (selon les fonctionnalités d&#39;OpenCode) :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Utilisez les outils de débogage pour afficher l&#39;historique des messages de session</span></span></code></pre></div><p><strong>Ce que vous devriez voir</strong> :</p><ul><li>Les messages de la liste des compétences récupérée sont marqués comme <code>synthetic: true</code></li><li>Ces messages ne s&#39;affichent pas dans l&#39;interface de conversation normale</li></ul><h2 id="point-de-controle-✅" tabindex="-1">Point de contrôle ✅ <a class="header-anchor" href="#point-de-controle-✅" aria-label="Permalink to &quot;Point de contrôle ✅&quot;">​</a></h2><p>Après avoir terminé les étapes ci-dessus, vous devriez pouvoir confirmer :</p><ul><li>[ ] L&#39;IA peut toujours accéder à la liste des compétences lors de longues sessions</li><li>[ ] La fonction de chargement des compétences fonctionne normalement après compression</li><li>[ ] Le processus de récupération est complètement transparent pour l&#39;utilisateur</li></ul><h2 id="avertissements-sur-les-pieges" tabindex="-1">Avertissements sur les pièges <a class="header-anchor" href="#avertissements-sur-les-pieges" aria-label="Permalink to &quot;Avertissements sur les pièges&quot;">​</a></h2><h3 id="probleme-1-apres-compression-l-ia-dit-competence-introuvable" tabindex="-1">Problème 1 : Après compression, l&#39;IA dit &quot;compétence introuvable&quot; <a class="header-anchor" href="#probleme-1-apres-compression-l-ia-dit-competence-introuvable" aria-label="Permalink to &quot;Problème 1 : Après compression, l&#39;IA dit &quot;compétence introuvable&quot;&quot;">​</a></h3><p><strong>Causes possibles</strong> :</p><ul><li>Le plugin n&#39;écoute pas correctement l&#39;événement <code>session.compacted</code></li><li>Le chemin du répertoire des compétences a changé</li></ul><p><strong>Solution</strong> :</p><ol><li><p><strong>Vérifier si l&#39;événement de compression est déclenché</strong></p><ul><li>À travers les étapes 3 et 4 de &quot;Suivez les étapes&quot;, confirmez que l&#39;IA peut toujours accéder à la liste des compétences après compression</li><li>Si l&#39;IA peut utiliser les compétences normalement, cela signifie que le mécanisme de récupération après compression fonctionne normalement</li></ul></li><li><p><strong>Vérifier si le plugin est correctement chargé</strong></p><ul><li>Redémarrez OpenCode</li><li>Après avoir démarré une nouvelle session, demandez à l&#39;IA de lister les compétences disponibles (<code>get_available_skills</code>)</li><li>Si vous pouvez voir la liste des compétences, cela signifie que le plugin est correctement chargé</li></ul></li></ol><h3 id="probleme-2-la-liste-des-competences-recuperee-est-vide" tabindex="-1">Problème 2 : La liste des compétences récupérée est vide <a class="header-anchor" href="#probleme-2-la-liste-des-competences-recuperee-est-vide" aria-label="Permalink to &quot;Problème 2 : La liste des compétences récupérée est vide&quot;">​</a></h3><p><strong>Causes possibles</strong> :</p><ul><li>Aucune compétence dans le chemin de découverte des compétences</li><li>Format de fichier de compétence incorrect</li></ul><p><strong>Solution</strong> :</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Requête manuelle des compétences disponibles</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Utilisez</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> get_available_skills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> pour</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> voir</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> liste</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> des</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compétences</span></span></code></pre></div><p>Si la liste vide est renvoyée, vérifiez le répertoire des compétences et le format des fichiers.</p><h3 id="probleme-3-etat-des-competences-chargees-perdu-apres-compression" tabindex="-1">Problème 3 : État des compétences chargées perdu après compression <a class="header-anchor" href="#probleme-3-etat-des-competences-chargees-perdu-apres-compression" aria-label="Permalink to &quot;Problème 3 : État des compétences chargées perdu après compression&quot;">​</a></h3><p><strong>Il s&#39;agit d&#39;un comportement attendu</strong>, pas d&#39;un bug. Le mécanisme de récupération vide l&#39;enregistrement <code>loadedSkillsPerSession</code>, permettant à l&#39;IA de réévaluer quelles compétences sont nécessaires.</p><p><strong>Solution</strong> : L&#39;IA décidera automatiquement s&#39;il faut recharger les compétences en fonction du contexte, sans intervention manuelle.</p><h2 id="resume-du-cours" tabindex="-1">Résumé du cours <a class="header-anchor" href="#resume-du-cours" aria-label="Permalink to &quot;Résumé du cours&quot;">​</a></h2><p>Le mécanisme de récupération après compression assure la disponibilité des compétences lors de longues sessions par les moyens suivants :</p><ol><li><strong>Écouter l&#39;événement de compression</strong> : Détecter automatiquement l&#39;événement <code>session.compacted</code></li><li><strong>Réinjecter la liste des compétences</strong> : Injecter toutes les compétences en utilisant la balise <code>&lt;available-skills&gt;</code></li><li><strong>Récupération Superpowers optionnelle</strong> : Si activé, récupérer également l&#39;invite Superpowers</li><li><strong>Utiliser des messages synthétiques</strong> : Le processus de récupération est transparent pour l&#39;utilisateur et n&#39;affecte pas la conversation</li><li><strong>Réinitialiser l&#39;enregistrement des compétences chargées</strong> : Vider l&#39;ensemble des compétences chargées, permettant une réévaluation</li></ol><p>Ce mécanisme assure que :</p><ul><li>Les compétences sont toujours disponibles lors de longues sessions</li><li>Le processus de récupération est automatisé et imperceptible</li><li>L&#39;IA peut décider quelles compétences utiliser en fonction du contexte le plus récent</li></ul><h2 id="apercu-du-prochain-cours" tabindex="-1">Aperçu du prochain cours <a class="header-anchor" href="#apercu-du-prochain-cours" aria-label="Permalink to &quot;Aperçu du prochain cours&quot;">​</a></h2><blockquote><p>Dans le prochain cours, nous apprendrons <strong><a href="./../../faq/troubleshooting/">Dépannage des problèmes courants</a></strong>.</p><p>Vous apprendrez :</p><ul><li>Méthodes de gestion des erreurs et exceptions courantes</li><li>Techniques de dépannage liées à la récupération après compression</li><li>Solutions à d&#39;autres problèmes d&#39;utilisation</li></ul></blockquote><hr><h2 id="annexe-reference-du-code-source" tabindex="-1">Annexe : Référence du code source <a class="header-anchor" href="#annexe-reference-du-code-source" aria-label="Permalink to &quot;Annexe : Référence du code source&quot;">​</a></h2><details><summary><strong>Cliquer pour afficher l&#39;emplacement du code source</strong></summary><blockquote><p>Date de mise à jour : 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Fonction</th><th>Chemin du fichier</th><th>Lignes</th></tr></thead><tbody><tr><td>Écoute de l&#39;événement de compression</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L144-L157" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>144-157</td></tr><tr><td>Initialisation du premier message</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L70-L105" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>70-105</td></tr><tr><td>Injection de la liste des compétences</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/skills.ts#L345-L370" target="_blank" rel="noreferrer"><code>src/skills.ts</code></a></td><td>345-370</td></tr><tr><td>Injection de messages synthétiques</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/utils.ts#L147-L162" target="_blank" rel="noreferrer"><code>src/utils.ts</code></a></td><td>147-162</td></tr><tr><td>Gestion de l&#39;état de session</td><td><a href="https://github.com/joshuadavidthomas/opencode-agent-skills/blob/main/src/plugin.ts#L25-L35" target="_blank" rel="noreferrer"><code>src/plugin.ts</code></a></td><td>25-35</td></tr></tbody></table><p><strong>Variables clés</strong> :</p><ul><li><code>setupCompleteSessions: Set&lt;string&gt;</code> : Enregistre les ID de sessions ayant terminé l&#39;initialisation</li><li><code>loadedSkillsPerSession: Map&lt;string, Set&lt;string&gt;&gt;</code> : Enregistre les noms des compétences chargées pour chaque session</li></ul><p><strong>Fonctions clés</strong> :</p><ul><li><code>injectSkillsList()</code> : Injecte la liste des compétences disponibles dans la session</li><li><code>injectSyntheticContent()</code> : Utilise des messages synthétiques pour injecter du contenu</li><li><code>getSessionContext()</code> : Obtient les informations de modèle et d&#39;agent de la session</li></ul></details>`,85)])])}const h=s(o,[["render",a]]);export{m as __pageData,h as default};
